solution_code:
#include <iostream>

template <typename T>
void describe(const T& v) {
    std::cout << "int: " << v << "\n";
}

template <>
void describe<bool>(const bool& v) {
    std::cout << "bool: " << (v ? "true" : "false") << "\n";
}

int main() {
    int n;
    std::cin >> n;
    describe(n);

    int b;
    std::cin >> b;
    describe(static_cast<bool>(b));

    return 0;
}

