solution_code:
#include <iostream>

template <typename T>
void format(T v) {
    std::cout << "Number: " << v << "\n";
}

template <>
void format<double>(double v) {
    std::cout << "Float: " << v << "\n";
}

int main() {
    int a;
    double b;
    std::cin >> a >> b;
    format(a);
    format(b);
    return 0;
}
